light.aceEditor:
.ace_editor {
   border: 1px solid #d4d5d7;
   border-radius: 5px;
 }

 .ace-graylog {
   background-color: #fff;
   color: #06050F;

   &.ace_multiselect .ace_selection.ace_start {
     box-shadow: 0 0 3px 0 #fff;
   }

   .ace_gutter {
     background: #FAF9FF;
     color: #06050F;
   }

   .ace_print-margin {
     width: 1px;
     background: #FAF9FF;
   }

   .ace_cursor {
     color: #362F62;
   }

   .ace_marker-layer {
     .ace_selection {
       background: #bfc0c3;
     }

     .ace_step {
       background: rgb(255 255 0);
     }

     .ace_bracket {
       margin: -1px 0 0 -1px;
       border: 1px solid #bfc0c3;
     }

     .ace_selected-word {
       border: 1px solid #a9abaf;
     }

     .ace_active-line {
       background: #CAC8D7;
     }
   }

   .ace_gutter-active-line {
     background-color: #CAC8D7;
   }

   .ace_invisible {
     color: #bfc0c3;
   }

   .ace_keyword,
   .ace_meta,
   .ace_storage,
   .ace_storage.ace_type,
   .ace_support.ace_type {
     color: #578dcc;
   }

   .ace_keyword.ace_operator {
     color: #006B8F;
   }

   .ace_constant.ace_character,
   .ace_constant.ace_language,
   .ace_constant.ace_numeric,
   .ace_keyword.ace_other.ace_unit,
   .ace_support.ace_constant,
   .ace_variable.ace_parameter {
     color: #01208C;
   }

   .ace_constant.ace_other {
     color: #0D0A1F;
   }

   .ace_invalid {
     color: #fff;
     background-color: #FE6E6D;
   }

   .ace_invalid.ace_deprecated {
     color: #fff;
     background-color: #023AFF;
   }

   .ace_fold {
     background-color: #03C2FF;
     border-color: #06050F;
   }

   .ace_entity.ace_name.ace_function,
   .ace_support.ace_function,
   .ace_variable {
     color: #03C2FF;
   }

   .ace_support.ace_class,
   .ace_support.ace_type {
     color: #7A6000;
   }

   .ace_heading,
   .ace_markup.ace_heading,
   .ace_string {
     color: #2E6F25;
   }

   .ace_entity.ace_name.ace_tag,
   .ace_entity.ace_other.ace_attribute-name,
   .ace_meta.ace_tag,
   .ace_string.ace_regexp,
   .ace_variable {
     color: #FE6E6D;
   }

   .ace_comment {
     color: #1A143E;
   }
 }

